  const g = gcd(gcd(Math.abs(a),Math.abs(b)),Math.abs(c));
  const prim = g===1;
  const defn = D<0&&a>0 ? 'positive-definite' : D<0&&a<0 ? 'negative-definite' : D===0 ? 'degenerate' : 'indefinite';
  out.textContent = `f(x,y) = ${a}x² ${b>=0?'+':''}${b}xy ${c>=0?'+':''}${c}y²\nD = ${b}²−4·${a}·${c} = ${D}\nType: ${defn}\nPrimitive: ${prim?'yes (gcd=1)':'no (gcd='+g+')'}`;

  /* draw the form as a heat-map on a small grid */
  svg.innerHTML = '';
  const N=8, W=460, H=200, cx=W/2, cy=H/2, sc=20;
  /* axes */
  const ax1=SVG('line',{x1:0,y1:cy,x2:W,y2:cy,stroke:'var(--line)',  'stroke-width':1});
  const ax2=SVG('line',{x1:cx,y1:0,x2:cx,y2:H,stroke:'var(--line)','stroke-width':1});
