  const xl=SVG('text',{x:W-8,y:cy-6,'text-anchor':'end','font-size':11,fill:'var(--mute)'}); xl.textContent='x'; svg.appendChild(xl);
  const yl=SVG('text',{x:cx+6,y:12,'font-size':11,fill:'var(--mute)'}); yl.textContent='y'; svg.appendChild(yl);

  let vmax=1;
