      const t = Math.max(-1,Math.min(1,v/vmax));
      let r,g2,bl;
      if(t>=0){ r=Math.round(255*(1-t)*0.3+255*t*0.3); g2=Math.round(100+155*(1-t)); bl=Math.round(50); }
      else { const s=-t; r=Math.round(200+55*s); g2=Math.round(70*(1-s)); bl=Math.round(60*(1-s)); }
