const aI=$('#ra'), bI=$('#rb'), cI=$('#rc'), btn=$('#red-btn'), out=$('#red-out');
function reduceForm(a,b,c){
  const D = b*b - 4*a*c;
  const steps=[];
  steps.push(`Start: (${a}, ${b}, ${c}), D = ${D}`);
  if(D>=0 || a<=0){ out.textContent='Need D < 0 and a > 0 for positive-definite reduction.'; return; }
  let iter=0;
  while(true){
    iter++;
    if(iter>200){ steps.push('(too many steps — aborting)'); break; }
    if(a > c){ [a,c]=[c,a]; b=-b; steps.push(`Swap a↔c, negate b → (${a}, ${b}, ${c})`); continue; }
    if(Math.abs(b) > a){
      const k = Math.floor((b+a)/(2*a));
      b = b - 2*a*k;
      c = (b*b - D)/(4*a);
      steps.push(`Shift b by -${2*a*k} → (${a}, ${b}, ${c})`);
      continue;
    }
    break;
  }
  /* tie-break */
  if(b < 0 && (Math.abs(b)===a || a===c)){ b=-b; }
  steps.push(`Reduced: (${a}, ${b}, ${c}) — primitive: ${gcd(gcd(Math.abs(a),Math.abs(b)),Math.abs(c))===1?'yes':'no'}`);
  out.textContent = steps.join('\n');
}
