const svg=$('#cg-svg'), out=$('#cg-out');
const forms=[
  {label:'(1,1,6)', name:'identity', color:'var(--yellow)'},
  {label:'(2,1,3)', name:'g', color:'var(--blue)'},
  {label:'(2,−1,3)', name:'g⁻¹', color:'var(--violet)'}
];
const cx=230, cy=110, R=80;
const pts=forms.map((_,i)=>({
  x: cx + R*Math.cos(-Math.PI/2 + 2*Math.PI*i/3),
  y: cy + R*Math.sin(-Math.PI/2 + 2*Math.PI*i/3)
}));

function draw(highlighted=-1){
  svg.innerHTML='';
  /* title */
  const t0=SVG('text',{x:230,y:20,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
  t0.textContent='Cl(−23) ≅ ℤ/3ℤ — three reduced forms, cyclic of order 3'; svg.appendChild(t0);

  /* curved arrows for the composition g+g=g⁻¹ and g+g⁻¹=e */
  const arrowDefs=[
    {from:0,to:1,lbl:'×g',c:-20},
    {from:1,to:2,lbl:'×g',c:-20},
    {from:2,to:0,lbl:'×g',c:-20}
  ];
  for(const {from,to,lbl,c} of arrowDefs){
    drawArrow(svg, [pts[from].x,pts[from].y],[pts[to].x,pts[to].y],
      {color:'var(--mute)',curve:c,label:lbl,markerId:'arr-cg'+from+to,pad1:24,pad2:24,width:1.2});
  }
  for(let i=0;i<forms.length;i++){
    const {x,y}=pts[i];
    const f=forms[i];
    const active = i===highlighted;
    svg.appendChild(SVG('circle',{cx:x,cy:y,r:28,
      fill:active?f.color:'var(--panel2)',
      stroke:f.color,'stroke-width':active?2.5:1.5,
      style:'cursor:pointer'}));
    const tl=SVG('text',{x,y:y-5,'text-anchor':'middle','font-size':11,
      fill:active?'#111':'var(--ink)','font-weight':600});
    tl.textContent=f.label; svg.appendChild(tl);
    const ts=SVG('text',{x,y:y+10,'text-anchor':'middle','font-size':10,
      fill:active?'#111':'var(--mute)'});
    ts.textContent=f.name; svg.appendChild(ts);

    svg.lastElementChild.parentNode; // no-op, keep structure
    const ci = i;
    svg.querySelectorAll('circle')[i+1]; // placeholder
  }

  /* make circles clickable — re-query after draw */
  const circles = [...svg.querySelectorAll('circle')];
  circles.forEach((circ,i)=>{
    circ.style.cursor='pointer';
    circ.addEventListener('click',()=>{
      const table=[
        ['e',  'g',   'g⁻¹'],
        ['g',  'g⁻¹', 'e'],
        ['g⁻¹','e',   'g']
      ];
      const names=forms.map(f=>f.name);
      let rows=`Multiplication table (row × col):\n    ${names.join('  ')}\n`;
      for(let r=0;r<3;r++){
        rows+=`${names[r].padEnd(4)} ${table[r].map(x=>x.padEnd(4)).join(' ')}\n`;
      }
      rows+=`\nSelected: ${forms[i].label} (${forms[i].name})`;
      out.textContent=rows;
      draw(i);
    });
  });
}
draw();

