/* Compute genus for a form (a,b,c) with discriminant D using Legendre symbols at odd primes dividing D */
function genusVector(a,b,c,D){
  /* find an m represented by f with gcd(m,D)=1 — try small values */
  function rep(a,b,c){
    for(let x=-10;x<=10;x++) for(let y=-10;y<=10;y++){
      const v=a*x*x+b*x*y+c*y*y;
      if(v>0 && gcd(Math.abs(v),Math.abs(D))===1) return v;
    }
    return a; /* fallback */
  }
  const m=rep(a,b,c);
  /* collect odd prime discriminant divisors */
  const Dabs=Math.abs(D); const primes=[];
  for(let p=3;p<=Dabs;p+=2){ if(isPrime(p) && Dabs%p===0) primes.push(p); }
  return {m, primes, chars: primes.map(p=>legendre(m,p))};
}

