    genera[key].push({a,b,c,m,chars,primes});
  }

  const genKeys=Object.keys(genera);
  info.textContent=`h(${D})=${forms.length}, genera=${genKeys.length}`;

  const colors=['genus-0','genus-1','genus-2','genus-3'];
  genKeys.forEach((key,gi)=>{
    const wrap=document.createElement('div');
    wrap.style.cssText='margin-bottom:.5rem;';
    const hdr=document.createElement('div');
    const g=genera[key];
    const charStr=g[0].primes.map((p,i)=>`(·/${p})=${g[0].chars[i]>=0?'+':''}${g[0].chars[i]}`).join(', ');
    hdr.innerHTML=`<span class="genus-chip ${colors[gi%4]}">Genus ${gi+1}: ${charStr||'principal'}</span>`;
    wrap.appendChild(hdr);
    const row=document.createElement('div');
    row.style.cssText='display:flex;flex-wrap:wrap;gap:4px;margin-top:3px;';
    for(const {a,b,c} of g){
      const chip=document.createElement('span');
      chip.className='form-chip';
      chip.textContent=`(${a},${b},${c})`;
      chip.addEventListener('click',()=>{
        out.textContent=`Form (${a},${b},${c}): represents m=${g.find(x=>x.a===a&&x.b===b)?.m||'?'}, D=${b*b-4*a*c}`;
      });
      row.appendChild(chip);
    }
    wrap.appendChild(row);
    disp.appendChild(wrap);
  });
}
