sel.value='-23';
const out=$('#split-out'), svg=$('#split-svg');

function sieveRep(D, limit){
  /* Find which primes p<=limit are represented by the principal form.
     Principal form for D<0: if D≡0 mod 4 → (1,0,-D/4); if D≡1 mod 4 → (1,1,(1-D)/4).
     We brute-force: check if p = f(x,y) for any small x,y. */
  let a,b,c;
  if(D%4===0){ a=1; b=0; c=-D/4; }
  else { a=1; b=1; c=(1-D)/4; }
  const primes=[];
  for(let p=2;p<=limit;p++){
    if(!isPrime(p)) continue;
    if(D%p===0) continue;
    let found=false;
    outer: for(let x=0;x<=p;x++) for(let y=0;y<=p;y++){
      if(a*x*x+b*x*y+c*y*y===p){ found=true; break outer; }
    }
    primes.push({p, rep:found});
  }
  return primes;
}

function render(){
  const D=parseInt(sel.value);
  const primes=sieveRep(D,100);
  const yes=primes.filter(x=>x.rep).map(x=>x.p);
  const no=primes.filter(x=>!x.rep).map(x=>x.p).slice(0,18);
  out.textContent=`Principal form of D=${D}:\nRepresented primes (≤100): ${yes.join(', ')}\nNot represented (first 18): ${no.join(', ')}`;

  svg.innerHTML='';
  const W=460, pad=10, step=Math.min(18,(W-2*pad)/primes.length);
  primes.slice(0,Math.floor((W-2*pad)/step)).forEach(({p,rep},i)=>{
    const x=pad+i*step+step/2;
    const col=rep?'var(--yellow)':'var(--panel2)';
    const bc=rep?'var(--yellow)':'var(--mute)';
    svg.appendChild(SVG('rect',{x:pad+i*step,y:20,width:step-2,height:60,
      fill:col,rx:3,opacity:rep?'0.25':'0.12',stroke:bc,'stroke-width':'0.5'}));
    const t=SVG('text',{x,y:55,'text-anchor':'middle','font-size':9,fill:rep?'var(--yellow)':'var(--mute)'});
    t.textContent=String(p); svg.appendChild(t);
  });
  const leg=SVG('text',{x:8,y:14,'font-size':9,fill:'var(--mute)'});
  leg.textContent='yellow = represented by principal form'; svg.appendChild(leg);
}
